// Object destructuring with defaults
const { name, role = 'viewer', active = true } = { name: 'Alice' };

console.log(name);   // 'Alice'
console.log(role);   // 'viewer'  — property absent, default used
console.log(active); // true      — property absent, default used

// Array destructuring with defaults
const [x = 0, y = 0, z = 0] = [10, 20];

console.log(x); // 10 — from array
console.log(y); // 20 — from array
console.log(z); // 0  — no element at index 2, default used

const { a = 'default', b = 'default', c = 'default', d = 'default' } = {
  a: null,       // null is NOT undefined → 'default' is NOT used
  b: 0,          // 0 is NOT undefined   → 'default' is NOT used
  c: false,      // false is NOT undefined → 'default' is NOT used
  d: '',         // '' is NOT undefined  → 'default' is NOT used
  // e is absent → undefined            → 'default' IS used
};

console.log(a); // null
console.log(b); // 0
console.log(c); // false
console.log(d); // ''

const { e = 'default' } = {};
console.log(e); // 'default'

function generateId() {
  console.log('generating id...');
  return Math.random().toString(36).slice(2);
}

const { id = generateId(), name } = { name: 'Alice', id: 'abc123' };
// generateId() is NOT called because id is present
console.log(id); // 'abc123'

const { id: id2 = generateId(), name: name2 } = { name: 'Bob' };
// generateId() IS called because id is absent
// logs 'generating id...'
console.log(id2); // e.g. 'k4f2x9'

const user = { id: 42, name: 'Alice', type: 'admin' };

// Extract 'id' as 'userId', 'name' as 'username', 'type' as 'userType'
const { id: userId, name: username, type: userType } = user;

console.log(userId);   // 42
console.log(username); // 'Alice'
console.log(userType); // 'admin'

// The original property names are NOT created as variables:
// console.log(id);   // ReferenceError
// console.log(name); // ReferenceError

const product = { name: 'Laptop', category: { name: 'Electronics' } };

// Both levels have 'name' — without aliasing one would shadow the other
const { name: productName, category: { name: categoryName } } = product;

console.log(productName);  // 'Laptop'
console.log(categoryName); // 'Electronics'

const apiResponse = { data: [1, 2, 3], status: 200 };

// 'data' is generic — alias it to describe what it actually is
const { data: scores, status: httpStatus } = apiResponse;

console.log(scores);     // [1, 2, 3]
console.log(httpStatus); // 200

const obj = { 'content-type': 'application/json', class: 'premium' };

// 'class' is a reserved word; 'content-type' contains a hyphen
const { 'content-type': contentType, class: userClass } = obj;

console.log(contentType); // 'application/json'
console.log(userClass);   // 'premium'

// Pattern: { originalKey: aliasName = defaultValue }
const config = { retries: 3 };

const {
  retries:     maxRetries    = 1,    // present → maxRetries = 3
  timeout:     requestTimeout = 5000, // absent  → requestTimeout = 5000
  verbose:     isVerbose     = false  // absent  → isVerbose = false
} = config;

console.log(maxRetries);     // 3
console.log(requestTimeout); // 5000
console.log(isVerbose);      // false

function Avatar({
  src,
  alt = 'User avatar',          // optional prop with default
  size = 40,                    // optional prop with default
  className: customClass = '',  // alias 'className' → 'customClass' with default
  onClick: handleClick = null   // alias 'onClick' → 'handleClick' with default
}) {
  const style = { width: size, height: size };

  return (
    <img
      src={src}
      alt={alt}
      style={style}
      className={`avatar ${customClass}`}
      onClick={handleClick}
    />
  );
}

// Parent passes 'value' and 'onChange', but the child works with 'text' and 'onTextChange'
function SearchInput({ value: text, onChange: onTextChange, placeholder = 'Search...' }) {
  return (
    <input
      type="text"
      value={text}
      onChange={onTextChange}
      placeholder={placeholder}
    />
  );
}

const user = { name: 'Alice' }; // no 'preferences' property

// ❌ TypeError — 'preferences' is undefined, can't destructure it
// const { preferences: { theme } } = user;

// ✅ Default empty object guards the intermediate level
const { preferences: { theme = 'light', language = 'en' } = {} } = user;

console.log(theme);    // 'light'
console.log(language); // 'en'

const { preferences: userPrefs = {} } = user;
// Now 'userPrefs' is either the preferences object or {}
// You can use it normally or destructure it further in a separate step
const { theme = 'light' } = userPrefs;

const { label = 'Default Label' } = { label: null };
console.log(label); // null  ❌ default was NOT applied

// null is not undefined — use nullish coalescing after extraction if needed:
const { label: rawLabel = undefined } = { label: null };
const finalLabel = rawLabel ?? 'Default Label';
console.log(finalLabel); // 'Default Label'  ✅

const obj = { originalKey: 'hello' };

// ✅ Correct: { propertyName: localVariableName }
const { originalKey: myVar } = obj; // myVar = 'hello'

// ❌ Wrong order — tries to look up 'myVar' on the object, not 'originalKey'
// const { myVar: originalKey } = obj; // originalKey = undefined

const { id: userId } = { id: 1 };

console.log(userId); // 1  ✅
console.log(id);     // ReferenceError ❌ — 'id' was never created as a variable

// When using both alias and default, the default goes after the alias:
const { timeout: delay = 3000 } = {};
console.log(delay); // 3000  ✅

// NOT like this — syntax error:
// const { timeout = 3000: delay } = {};  ❌
